// 1. AUTH — 2-STEP: LOGIN SCREEN → PIN
// ══════════════════════════════════════════════════════════════
let currentUser  = '';
let currentEmail = '';
const CORRECT_PIN = '2026';
let pinEntry = '';
let isReadOnly = false;

/* ── STEP 1: Name + Email ─────────────────────────────────── */
function loginContinue(){
  const nameEl  = document.getElementById('login-name');
  const emailEl = document.getElementById('login-email');
  const errEl   = document.getElementById('login-err');

  const name  = (nameEl  ? nameEl.value  : '').trim();
  const email = (emailEl ? emailEl.value : '').trim();

  if(!name){
    if(errEl) errEl.textContent = 'Please enter your full name.';
    return;
  }
  if(!email || !email.includes('@')){
    if(errEl) errEl.textContent = 'Please enter a valid email.';
    return;
  }

  currentUser  = name;
  currentEmail = email;

  // Instant switch — no animation to avoid iOS timing issues
  const lo = document.getElementById('login-overlay');
  const po = document.getElementById('pin-overlay');
  if(lo) lo.style.display = 'none';
  if(po) po.style.display = 'flex';

  const sub = document.querySelector('#pin-overlay .pin-sub');
  if(sub) sub.textContent = 'Welcome, ' + name.split(' ')[0] + ' · Enter your PIN';
}

/* ── STEP 2: PIN ──────────────────────────────────────────── */
function pinKey(k){
  if(pinEntry.length >= 4) return;
  pinEntry += k;
  updatePinDots();
  if(pinEntry.length === 4) setTimeout(checkPin, 120);
}
function pinDel(){
  pinEntry = pinEntry.slice(0,-1);
  updatePinDots();
}
function updatePinDots(err=false){
  for(let i=0;i<4;i++){
    const d = document.getElementById('pd'+i);
    if(!d) continue;
    d.classList.toggle('filled', i < pinEntry.length && !err);
    d.classList.toggle('error',  err && i < pinEntry.length);
  }
}
function checkPin(){
  if(pinEntry === CORRECT_PIN){
    const po = document.getElementById('pin-overlay');
    if(po){ po.style.transition='opacity .4s'; po.style.opacity='0'; }
    setTimeout(()=>{ if(po) po.style.display='none'; }, 400);
    isReadOnly = false;
    setTimeout(()=>showToast('✅ Welcome, ' + (currentUser.split(' ')[0]||'!')), 450);
  } else {
    updatePinDots(true);
    const msg = document.getElementById('pin-msg');
    if(msg) msg.textContent = 'PIN incorrecto';
    setTimeout(()=>{ pinEntry=''; updatePinDots(); if(msg) msg.textContent=''; }, 900);
  }
}
function enterReadOnly(){
  ['login-overlay','pin-overlay'].forEach(id=>{
    const el = document.getElementById(id);
    if(el) el.style.display='none';
  });
  currentUser  = 'Guest';
  currentEmail = '';
  isReadOnly   = true;
  document.querySelectorAll('.status-step, [onclick="saveVenueAssignment()"], #loc-capture-btn, label[for="photo-input"], .import-btn, #excel-input')
    .forEach(el=>{ if(el) el.style.display='none'; });
  showToast('👁 View only mode');
}

/* ── Init ──────────────────────────────────────────────────── */
window.addEventListener('load', ()=>{
  emailjs.init('-7R-WGSWEXH7vT1Xj');

  // Wire login button
  const btn = document.getElementById('login-btn');
  if(btn) btn.addEventListener('click', loginContinue);

  // Enter key on login fields
  ['login-name','login-email'].forEach(id=>{
    const el = document.getElementById(id);
    if(el) el.addEventListener('keydown', e=>{ if(e.key==='Enter') loginContinue(); });
  });

  // Wire logout buttons (header + sidebar)
  ['logout-btn','logout-btn-sidebar'].forEach(id=>{
    const el = document.getElementById(id);
    if(el) el.addEventListener('click', handleSignOut);
  });
});

function handleSignOut(){
  firebase.auth().signOut();
  // onAuthStateChanged fires with null → redirects to login.html automatically
}

function guardEdit(){
  if(isReadOnly){ showToast('🔒 Solo lectura — PIN requerido'); return false; }
  return true;
}

