// ══════════════════════════════════════════════════════════════
// Uses EmailJS free tier — configure with your account
const EMAILJS_SERVICE = 'service_17309zo';
const EMAILJS_TEMPLATE = 'template_3em34jk';
const EMAILJS_KEY = '-7R-WGSWEXH7vT1Xj';
const NOTIFY_EMAIL = 'efr@popatelier.net';

async function sendInstallNotification(unit){
  try{
    if(typeof emailjs === 'undefined'){
      console.warn('EmailJS not loaded');
      return;
    }
    const ts = new Date().toLocaleString('en-US',{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});
    const installed = DATA.filter(d=>d.status==='Installed at Venue').length;
    const msg = `Unit installed at POS\n\nSerial: ${unit.digitalHeader}\nModel: ${unit.model}\nVenue: ${unit.venue||'—'}\nZone: ${unit.venueArea||'—'}\nSection: ${unit.section||'—'}\nLocation: ${unit.location||'—'}\nTechnician: ${unit.technician||'—'}\nTime: ${ts}\n\nProgress: ${installed}/${DATA.length} units installed`;

    const result = await emailjs.send(EMAILJS_SERVICE, EMAILJS_TEMPLATE, {
      title: `✅ Installed — ${unit.digitalHeader}`,
      name: unit.technician || 'Field Tech',
      time: ts,
      message: msg,
      email: NOTIFY_EMAIL
    });
    console.log('Email sent:', result.status, result.text);
    showToast('📧 Notificación enviada');
  }catch(e){
    console.error('Email failed:', e);
    showToast('⚠ Email: ' + (e.text || e.message || JSON.stringify(e)));
  }
}

