function updateVenueProgress(){
  const venues = ['metlife','lincoln','rockefeller'];
  venues.forEach(v=>{
    const total = DATA.filter(d=>d.venue===v).length;
    const installed = DATA.filter(d=>d.venue===v && d.status==='Installed at Venue').length;
    const el = document.getElementById('venue-progress-'+v);
    if(el) el.textContent = `${installed}/${total} installed`;
  });
}

