async function saveVenueAssignment(){
  if(!currentModalId){ showToast('No unit selected'); return; }
  const venue = document.getElementById('m-venue-sel').value;
  const zone  = document.getElementById('m-zone-sel').value;

  const btn = document.querySelector('[onclick="saveVenueAssignment()"]');
  if(btn){ btn.textContent='⏳ Saving…'; btn.disabled=true; }

  // If no venue selected → unassign (clear venue + zone)
  const isUnassigning = !venue;
  if(isUnassigning){
    try{
      const tech = currentUser || 'Unknown';
      await db.collection(COLLECTION).doc(currentModalId).update({
        venue: firebase.firestore.FieldValue.delete(),
        venueArea: firebase.firestore.FieldValue.delete(),
        unassignedAt: firebase.firestore.FieldValue.serverTimestamp(),
        unassignedBy: tech,
        updatedBy: currentUser || 'Unknown',
        updatedByEmail: currentEmail || '',
        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
      });
      // Log to history subcollection
      await db.collection(COLLECTION).doc(currentModalId).collection('history').add({
        action: 'venue_unassigned',
        by: tech,
        timestamp: firebase.firestore.FieldValue.serverTimestamp(),
        note: 'Removed from venue assignment'
      });
      showToast('✓ Removed from venue · ' + tech);
      const d = DATA.find(x=>x.id===currentModalId);
      if(d){ delete d.venue; delete d.venueArea; }
      if(btn){ btn.textContent='📍 Save Location Assignment'; btn.disabled=false; }
    }catch(e){
      showToast('⚠ Could not save: ' + e.message);
      if(btn){ btn.textContent='📍 Save Location Assignment'; btn.disabled=false; }
    }
    return;
  }

  if(!zone){ showToast('⚠ Select a zone'); btn.disabled=false; btn.textContent='📍 Save Location Assignment'; return; }

  try{
    const tech = currentUser || 'Unknown';
    // Direct Firestore update — bypass safeUpdate to avoid offline queue issues
    await db.collection(COLLECTION).doc(currentModalId).update({
      venue: venue,
      venueArea: zone,
      updatedBy: currentUser || 'Unknown',
      updatedByEmail: currentEmail || '',
      updatedAt: firebase.firestore.FieldValue.serverTimestamp()
    });
    // Log to history subcollection
    await db.collection(COLLECTION).doc(currentModalId).collection('history').add({
      action: 'venue_assigned',
      venue: venue,
      venueArea: zone,
      by: tech,
      timestamp: firebase.firestore.FieldValue.serverTimestamp()
    });
    const venueName = VENUES[venue]?.name?.split('—')[0].trim() || venue;
    showToast('✓ ' + venueName + ' · ' + zone);
    // Update local DATA immediately
    const d = DATA.find(x=>x.id===currentModalId);
    if(d){ d.venue=venue; d.venueArea=zone; }
    if(btn){ btn.textContent='📍 Save Location Assignment'; btn.disabled=false; }
  }catch(e){
    showToast('⚠ Could not save: ' + e.message);
    console.error(e);
    if(btn){ btn.textContent='📍 Save Location Assignment'; btn.disabled=false; }
  }
}

async function captureLocation(){
  if(!currentModalId){ showToast('No unit selected'); return; }
  const btn = document.getElementById('loc-capture-btn');
  const locEl    = document.getElementById('m-loc');
  const coordsEl = document.getElementById('m-coords');
  const mapsLink = document.getElementById('m-maps-link');

  btn.textContent = '⏳ Getting GPS…';
  btn.style.opacity = '.5';
  btn.disabled = true;

  if(!navigator.geolocation){
    showToast('⚠ Geolocation not supported');
    btn.textContent = '📍 Capture Location';
    btn.style.opacity = '1'; btn.disabled = false;
    return;
  }

  navigator.geolocation.getCurrentPosition(async pos=>{
    const lat = pos.coords.latitude;
    const lng = pos.coords.longitude;
    const acc = Math.round(pos.coords.accuracy);

    // Update UI immediately with coords
    locEl.textContent = 'Getting address…';
    locEl.className = 'field-val';
    coordsEl.textContent = `${lat.toFixed(6)}°, ${lng.toFixed(6)}° · ±${acc}m`;
    coordsEl.style.display = 'block';
    mapsLink.href = `https://maps.google.com/maps?daddr=${lat},${lng}&dirflg=w`;
    mapsLink.style.display = 'flex';

    // Reverse geocode via OpenStreetMap Nominatim (free, no API key)
    let address = '—';
    try{
      const r = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`);
      const geo = await r.json();
      if(geo && geo.display_name){
        // Clean up address: take first 3 parts
        const parts = geo.display_name.split(',').slice(0,4).map(s=>s.trim());
        address = parts.join(', ');
      }
    }catch(e){ address = `${lat.toFixed(4)}, ${lng.toFixed(4)}`; }

    locEl.textContent = address;

    // Save to Firestore
    try{
      await safeUpdate(currentModalId, {
        lat: lat.toString(),
        lng: lng.toString(),
        location: address,
        locationAccuracy: acc,
        locationCapturedAt: firebase.firestore.FieldValue.serverTimestamp()
      });
      showToast('📍 Location saved');
    }catch(e){
      showToast('⚠ Could not save location');
      console.error(e);
    }

    btn.textContent = '📍 Update Location';
    btn.style.opacity = '1'; btn.disabled = false;
    const cb = document.getElementById('loc-clear-btn');
    if(cb) cb.style.display = 'flex';

  }, err=>{
    const msgs = {1:'Permission denied',2:'Position unavailable',3:'Timeout'};
    showToast('⚠ ' + (msgs[err.code]||'GPS error'));
    btn.textContent = '📍 Capture Location';
    btn.style.opacity = '1'; btn.disabled = false;
  },{
    enableHighAccuracy: true,
    timeout: 15000,
    maximumAge: 0
  });
}

async function clearLocation(){
  if(!currentModalId){ showToast('No unit selected'); return; }
  if(!confirm('Clear GPS location for this header?\n\nThis will remove the captured address and coordinates. The header will need to be re-captured.')) return;

  const locEl    = document.getElementById('m-loc');
  const coordsEl = document.getElementById('m-coords');
  const mapsLink = document.getElementById('m-maps-link');
  const clearBtn = document.getElementById('loc-clear-btn');
  const captureBtn = document.getElementById('loc-capture-btn');

  try{
    await safeUpdate(currentModalId, {
      lat: firebase.firestore.FieldValue.delete(),
      lng: firebase.firestore.FieldValue.delete(),
      location: '—',
      locationAccuracy: firebase.firestore.FieldValue.delete(),
      locationCapturedAt: firebase.firestore.FieldValue.delete()
    });
    // Reset UI
    locEl.textContent = '—';
    locEl.className = 'field-val pending';
    coordsEl.style.display = 'none';
    mapsLink.style.display = 'none';
    if(clearBtn) clearBtn.style.display = 'none';
    if(captureBtn) captureBtn.textContent = '📍 Capture Location';
    showToast('🗑 Location cleared');
  }catch(e){
    showToast('⚠ Could not clear location');
    console.error(e);
  }
}


// ── OFFLINE QUEUE ──────────────────────────────────────────────────────────
const OFFLINE_KEY = 'liberty_offline_queue';

function getQueue(){ try{ return JSON.parse(localStorage.getItem(OFFLINE_KEY)||'[]'); }catch(e){ return []; } }
function saveQueue(q){ localStorage.setItem(OFFLINE_KEY, JSON.stringify(q)); }

async function safeUpdate(docId, data){
  // Remove serverTimestamp for offline storage (not serializable)
  const offlineData = {...data};
  delete offlineData.updatedAt;
  delete offlineData.locationCapturedAt;

  if(!navigator.onLine){
    const q = getQueue();
    q.push({docId, data: offlineData, ts: Date.now()});
    saveQueue(q);
    // Update local DATA immediately
    const d = DATA.find(x=>x.id===docId);
    if(d) Object.assign(d, offlineData);
    showToast('📶 Saved offline — will sync when online');
    return;
  }
  await db.collection(COLLECTION).doc(docId).update({
    ...data,
    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
  });
}

async function syncOfflineQueue(){
  const q = getQueue();
  if(!q.length) return;
  showToast(`🔄 Syncing ${q.length} offline changes…`);
  let synced = 0;
  const failed = [];
  for(const item of q){
    try{
      await db.collection(COLLECTION).doc(item.docId).update({
        ...item.data,
        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
      });
      synced++;
    }catch(e){ failed.push(item); }
  }
  saveQueue(failed);
  if(synced > 0) showToast(`✓ ${synced} changes synced`);
}

window.addEventListener('online', ()=>{
  showToast('🌐 Back online');
  setTimeout(syncOfflineQueue, 1000);
});

// Check queue on load
window.addEventListener('load', ()=>{ if(navigator.onLine) setTimeout(syncOfflineQueue, 3000); });

