  if(ws[photoCell]) ws[photoCell].s = {font:{bold:true,color:{rgb:'F40009'}}};

  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, d.digitalHeader);
  XLSX.writeFile(wb, `${d.digitalHeader}_Liberty.xlsx`);
