// ── EXCEL IMPORT ────────────────────────────────
let importRows = [];

function triggerImport(){ document.getElementById('excel-input').click(); }

function handleExcelFile(e){
  const file = e.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = ev=>{
    try{
      const wb = XLSX.read(ev.target.result, {type:'binary'});
      const ws = wb.Sheets[wb.SheetNames[0]];

      // Read once from row 0; if column detection fails to find the digital header column,
      // re-read skipping title/blank rows (range:2 = row index 2 becomes the header)
      let raw = XLSX.utils.sheet_to_json(ws, {defval:''});
      if(!raw.length){ showToast('⚠ Empty file'); return; }

      const tryDetect = (rows)=>{
        const keys = Object.keys(rows[0]||{});
        const detect = (hints)=>{
          for(const h of hints){
            const found=keys.find(k=>k.toLowerCase().includes(h.toLowerCase()));
            if(found) return found;
          }
          return null;
        };
        return detect(['digital header','zipdhe','zipkdhi','header s/n','dh s/n','unit serial']);
      };

      // If first attempt doesn't find the header column, skip title rows
      if(!tryDetect(raw)){
        raw = XLSX.utils.sheet_to_json(ws, {defval:'', range:2});
      }
      // Still nothing? Try range:1
      if(!raw.length || !tryDetect(raw)){
        raw = XLSX.utils.sheet_to_json(ws, {defval:'', range:1});
      }

      if(!raw.length){ showToast('⚠ Empty file'); return; }

      // Auto-detect column mapping (case-insensitive, flexible)
      const keys = Object.keys(raw[0]);
      const detect = (hints)=>{
        for(const h of hints){
          const found=keys.find(k=>k.toLowerCase().includes(h.toLowerCase()));
          if(found) return found;
        }
        return null;
      };

      const colMap = {
        digitalHeader: detect(['unit serial number','digital header','zipdhe','zipkdhi','header s/n','dh s/n']),
        controllerSN:  detect(['número de serie','numero de serie','controller s/n','controller serial','popa serial','stix serial']),
        routerSN:      detect(['router','rtr s/n','router s/n','router serial']),
        simCard:       detect(['sim','sim card','sim #']),
        location:      detect(['location','loc','store','address','ubicacion','ubicación']),
        venue:         detect(['venue','estadio','stadium']),
        content:       detect(['content','contenido','playlist']),
        status:        detect(['instalado','installed','status','estatus']),
        ipAddress:     detect(['ip address','ip','ip addr']),
        macAddress:    detect(['mac address','mac','mac addr']),
        section:       detect(['section','seccion','sección','sec #']),
        technician:    detect(['technician','tech','instalador','installer','técnico']),
        notes:         detect(['notes','notas','comments','comentarios']),
      };

      // Filter only rows that have a digitalHeader value matching our data
      // Normalize: trim, uppercase, remove all whitespace
      const normalize = (s)=>String(s||'').trim().toUpperCase().replace(/\s+/g,'');
      const validIDs = new Set(DATA.map(d=>normalize(d.digitalHeader)));

      // Auto-correct common typos: ZIPDEH → ZIPDHE, ZIKPDHI → ZIPKDHI
      const autoCorrect = (s)=>{
        let fixed = s;
        // Common typo: D-E-H instead of D-H-E
        if(/^ZIPDEH/.test(fixed)) fixed = fixed.replace(/^ZIPDEH/, 'ZIPDHE');
        // Common typo: ZIKPDHI instead of ZIPKDHI
        if(/^ZIKPDHI/.test(fixed)) fixed = fixed.replace(/^ZIKPDHI/, 'ZIPKDHI');
        return fixed;
      };

      const allRowsWithDH = raw.filter(r=>{
        const dh = colMap.digitalHeader ? String(r[colMap.digitalHeader]).trim() : '';
        return dh.length > 0;
      });

      const unmatched = [];
      const autoFixed = [];
      importRows = raw.filter(r=>{
        const dhRaw = colMap.digitalHeader ? String(r[colMap.digitalHeader]).trim() : '';
        let dh = normalize(dhRaw);
        if(!dh) return false;
        if(validIDs.has(dh)) return true;
        // Try auto-correction
        const corrected = autoCorrect(dh);
        if(corrected !== dh && validIDs.has(corrected)){
          autoFixed.push(`${dhRaw} → ${corrected}`);
          // Update the row so the digitalHeader is corrected for the actual update step
          if(colMap.digitalHeader) r[colMap.digitalHeader] = corrected;
          return true;
        }
        unmatched.push(dhRaw);
        return false;
      });

      // Re-write digitalHeader column in matched rows to use normalized ID
      // so that the actual update step finds them in DATA
      importRows.forEach(r=>{
        if(colMap.digitalHeader){
          r[colMap.digitalHeader] = normalize(r[colMap.digitalHeader]);
        }
      });

      // Build status message
      let subMsg = `<b style="color:var(--text)">${importRows.length} matching rows</b> found in <i>${file.name}</i>.`;
      if(autoFixed.length > 0){
        subMsg += `<br><span style="color:#3b82f6;font-size:11px">✓ ${autoFixed.length} typos auto-corrected: ${autoFixed.slice(0,3).join(', ')}${autoFixed.length>3?'...':''}</span>`;
      }
      if(unmatched.length > 0){
        subMsg += `<br><span style="color:#f59e0b;font-size:11px">⚠ ${unmatched.length} unmatched: ${unmatched.slice(0,5).map(s=>`"${s}"`).join(', ')}${unmatched.length>5?'...':''}</span>`;
      }
      subMsg += `<br>Fields to update:`;

      document.getElementById('import-sub').innerHTML = subMsg;

      document.getElementById('import-map').innerHTML = Object.entries(colMap)
        .filter(([,v])=>v)
        .map(([k,v])=>`
          <div class="import-map-row">
            <span class="import-map-key">${k}</span>
            <span class="import-map-val">← "${v}"</span>
          </div>`).join('');

      document.getElementById('import-count').textContent = importRows.length;
      document.getElementById('import-progress').textContent='';
      document.getElementById('import-actions').style.display='flex';
      document.getElementById('import-overlay').classList.add('open');
      document.getElementById('import-overlay').dataset.colmap = JSON.stringify(colMap);

    }catch(err){
      showToast('⚠ Could not read file');
      console.error(err);
    }
  };
  reader.readAsBinaryString(file);
  e.target.value='';
}

async function confirmImport(){
  const colMap = JSON.parse(document.getElementById('import-overlay').dataset.colmap||'{}');
  document.getElementById('import-actions').style.display='none';
  const prog = document.getElementById('import-progress');
  prog.textContent=`Updating 0 / ${importRows.length}…`;

  const BATCH_SIZE=400;
  let updated=0;

  for(let i=0;i<importRows.length;i+=BATCH_SIZE){
    const batch=db.batch();
    const chunk=importRows.slice(i,i+BATCH_SIZE);
    chunk.forEach(row=>{
      const dh = colMap.digitalHeader ? String(row[colMap.digitalHeader]).trim() : '';
      if(!dh) return;
      const upd={updatedAt:firebase.firestore.FieldValue.serverTimestamp()};
      const str = (v)=>v!==undefined&&v!==null&&String(v).trim()!=='nan'&&String(v).trim()!==''?String(v).trim():'—';
      if(colMap.routerSN)     upd.routerSN     = str(row[colMap.routerSN]);
      if(colMap.simCard)      upd.simCard       = str(row[colMap.simCard]);
      if(colMap.controllerSN) upd.controllerSN  = str(row[colMap.controllerSN]);
      if(colMap.location)     upd.location      = str(row[colMap.location]);
      if(colMap.venue){
        const vText = str(row[colMap.venue]).toLowerCase();
        upd.venueText = str(row[colMap.venue]);
        // Map venue name to internal venue ID
        if(vText.includes('metlife'))           upd.venue = 'metlife';
        else if(vText.includes('lincoln'))      upd.venue = 'lincoln';
        else if(vText.includes('rockefeller'))  upd.venue = 'rockefeller';
      }
      if(colMap.content)      upd.content       = str(row[colMap.content]);
      if(colMap.ipAddress)    upd.ipAddress     = str(row[colMap.ipAddress]);
      if(colMap.macAddress)   upd.macAddress    = str(row[colMap.macAddress]);
      if(colMap.section)      upd.section       = str(row[colMap.section]);
      if(colMap.technician)   upd.technician    = str(row[colMap.technician]);
      if(colMap.notes)        upd.notes         = str(row[colMap.notes]);
      if(colMap.status){
        const sv = str(row[colMap.status]);
        if(sv && sv!=='—' && sv!=='NaN') upd.status = sv==='1'||sv.toLowerCase().includes('instal')?'Installed at Venue':sv;
      }
      batch.update(db.collection(COLLECTION).doc(dh), upd);
    });
    await batch.commit();
    updated+=chunk.length;
    prog.textContent=`Updating ${updated} / ${importRows.length}…`;
  }

  prog.textContent=`✓ ${updated} rows updated`;
  showToast(`✓ Imported ${updated} records`);
  setTimeout(closeImportOverlay, 1500);
}

function closeImportOverlay(){
  document.getElementById('import-overlay').classList.remove('open');
  importRows=[];
}

// ── PAGE SWITCH ──────────────────────────────────
function kpiFilter(platform, status){
  // Switch to inventory tab
  filterPlatform = platform;
  filterStatus   = status;
  filterVenue    = '';
  filterQ        = '';
  document.getElementById('q').value = '';

  // Update platform chips
  document.querySelectorAll('.chip').forEach(c=>c.classList.remove('active'));
  const chipMap = {'all':'cf-all','POPA':'cf-nav','KOS':'cf-kos'};
  const chip = document.getElementById(chipMap[platform]||'cf-all');
  if(chip) chip.classList.add('active');

  // Update status filter chips
  document.querySelectorAll('.sf').forEach(c=>c.classList.remove('active'));
  document.querySelectorAll('.sf').forEach(c=>{
    if(c.dataset.s === status) c.classList.add('active');
    if(!status && c.dataset.s === '') c.classList.add('active');
  });

  // Navigate to inventory tab
  const inventoryTab = document.querySelector('.tab[onclick*="inventory"]');
  showPage('inventory', inventoryTab);
  renderList();
}

// ── SWIPE BETWEEN TABS ──────────────────────────────────────────────────────
const PAGE_ORDER = ['overview','inventory','map'];
let touchStartX = 0, touchStartY = 0;

document.addEventListener('touchstart', e=>{
  touchStartX = e.touches[0].clientX;
  touchStartY = e.touches[0].clientY;
}, {passive:true});

document.addEventListener('touchend', e=>{
  const dx = e.changedTouches[0].clientX - touchStartX;
  const dy = e.changedTouches[0].clientY - touchStartY;
  if(Math.abs(dx) < 50 || Math.abs(dy) > Math.abs(dx)) return; // not a horizontal swipe
  // Don't swipe if inside modal or overlay
  if(document.getElementById('overlay').classList.contains('open')) return;
  const currentPage = document.querySelector('.page.active')?.id?.replace('page-','');
  const idx = PAGE_ORDER.indexOf(currentPage);
  if(idx === -1) return;
  const nextIdx = dx < 0 ? Math.min(idx+1, PAGE_ORDER.length-1) : Math.max(idx-1, 0);
  if(nextIdx === idx) return;
  const tabEl = document.querySelector('.tab[onclick*="'+PAGE_ORDER[nextIdx]+'"');
  if(tabEl) showPage(PAGE_ORDER[nextIdx], tabEl);
}, {passive:true});


